INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-0489de64-moex-00701', 'elementary-0489de64', 'elementary-0489de64-moex-111-01c5eaab', 'sub-elementary-0489de64-05', NULL, 'single_choice', '「臺北的家老了，真的成了老家。原本家裡的出入口裝的都是木門，很輕，把手是圓形的金屬，握 上去總是冰涼的，門板的配色很老氣，白色與膚橘色，還貼了許多早已倒閉的連鎖餐廳的招牌貼紙： 大頭黃鳥頂著一頭桃色的羽毛。門板表層的角落，因為老舊與濕氣微微翹起，緩慢露出其下的木頭 紋理。然而，這一切從來不曾讓我感到時光流逝，只是自然地隨時間接受它們的樣貌。」請問本文 的寫作重點是：', '["用細膩的筆觸，委婉地表達家具陳舊的感覺", "運用視覺、聽覺與觸覺強調家真的該裝修了", "用冷靜的敘述方式表達對於時光流逝的無奈", "仔細描寫各樣物件傳達接受家已變老的事實"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:01+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00702', 'elementary-0489de64', 'elementary-0489de64-moex-111-01c5eaab', 'sub-elementary-0489de64-05', NULL, 'single_choice', '「旗津沙灘流失速度愈來愈快，但旗津是觀光島，民眾來到旗津，多半是要到旗津海岸戲水，如果 沒有沙灘，旗津就失去吸引力，所以工程的建立與成敗都具有指標性意義。但以往保護海岸線的方 式，通常是在海岸線放置消波塊，但如此一來，沙灘將不復存在。」 根據上文判斷，作者認為：', '["消波塊不會嚴重破壞旗津沙灘的景觀", "民眾到旗津戲水的雅興不受消波塊影響", "保存沙灘應採放置消波塊之外的新工法", "放置消波塊能真正確保海岸沙灘的完整性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:01+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00703', 'elementary-0489de64', 'elementary-0489de64-moex-111-01c5eaab', 'sub-elementary-0489de64-05', NULL, 'single_choice', '「遠處，秧針半吐的水田，如棋盤一樣整齊排列；近處，無心散落的綠色棋子，閒閒地被灑在局外， 可是走得更近了，棋子擴大成深碧的卵石，你才猛然醒悟，那成點狀分布的碧綠，竟是臥在沙地上 安恬地曬著太陽的□□， 一刀剖下，碧沈與朱紅，或是碧沈與金黃的鮮活對比，都不是其他一清二 白的遠親所能夠望其項背的。」 根據上文，□□最適合填入的是：', '["鳳梨", "番薯", "西瓜", "苦瓜"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:01+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00704', 'elementary-0489de64', 'elementary-0489de64-moex-111-01c5eaab', 'sub-elementary-0489de64-05', NULL, 'single_choice', '「探險應該不是單純地走過很多表面上的距離，而應該是一種深入的研究：一件一閃即逝的小插曲， 一片風景的片面，或是一句偶然旁聽到的話，可能就是了解及解釋整個區域的唯一關鍵所在，如果 缺少那個關鍵，整個區域可能就一直不具任何意義。」 根據上文，最接近文意的選項為：', '["行萬里路不如讀萬卷書，不可忽視知識", "想要瞭解整個區域，必須深入危險之地", "區域研究的關鍵在於是否能掌握避險秘訣", "探險除外在的移動外，還須用心體察細節"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:01+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00705', 'elementary-0489de64', 'elementary-0489de64-moex-111-01c5eaab', 'sub-elementary-0489de64-05', NULL, 'single_choice', '「然而生命也許就是這樣的吧，無論是歡喜或悲傷，總值得我們認認真真的走一趟。我有著這麼多 這麼好的朋友陪我一起走這一條路，你說，我怎麼能不希望這一段路途可以更長更久一點呢？」 根據上文，因為有許多好朋友，才使得生命：', '["值得依戀", "更長更久", "幸福美滿", "多采多姿"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:01+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00706', 'elementary-0489de64', 'elementary-0489de64-moex-111-01c5eaab', 'sub-elementary-0489de64-05', NULL, 'single_choice', '「不知道走哪條路可抵達想去的地方，可能是阿茲海默氏症的早期徵候，原因在於大腦中最先被這 種疾病破壞的區域之一是內嗅皮質，那是我們感知自身位置的關鍵部位。研究人員讓45名有輕度認 知障礙的患者，根據虛擬實境頭盔上所見，找出虛擬的步行路徑。表現最差的受試者，腦脊液中阿 茲海默氏症的生物標記均呈陽性反應。虛擬實境測試或許可成為有效的診斷工具。」 這段文字最適合的標題是：', '["內嗅皮質與阿茲海默氏症的關係", "阿茲海默氏症的典型症狀與治療", "檢測阿茲海默氏症的有效新方法", "虛擬實境與阿茲海默氏症的治療"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:01+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00707', 'elementary-0489de64', 'elementary-0489de64-moex-111-01c5eaab', 'sub-elementary-0489de64-05', NULL, 'single_choice', '「職場上，開個玩笑、展現幽默，可收人際潤滑，改善工作氛圍之效，但運用不當，反而弄巧成拙。 身為主管，領導才是最重要的任務，而非調笑。朋友間開玩笑，或無傷大雅，但主管跟部屬開玩笑， 未必是幽默。部屬與長官開玩笑更得審慎，因為玩笑是否幽默，決定權向來在對方。如果對方不覺 幽默，那一番好意倒成惡意。即便開自己玩笑，也不一定幽默，很可能因此傷人而不自知。尤其領 導者代表的並非個人，開自己玩笑時，很可能已經傷害了團隊。鼓動幽默時，我們要覺察自己的動 機，注意表現的時機，留心他人的反應。須避免譏諷性與戲弄性的言語，以免傷害他人。幽默固然 有諸多好處，但若自己個性實在不適合，就不必勉強。」 根據上文，下列敘述不符合文意的是：', '["開玩笑得要注意自己身分", "玩笑出於善意則不會傷人", "幽默得搭配適當表達時機", "自嘲也是幽默的一種方式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:01+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00708', 'elementary-0489de64', 'elementary-0489de64-moex-111-01c5eaab', 'sub-elementary-0489de64-05', NULL, 'single_choice', '「『美』，只在瞬間出現，有時候根本不容人靠近，宛如在雲霧掩擁裡汪洋上的孤絕之島，偶一現 身之後，總讓人懷疑剛才是不是真的見過她。譬如泰姬瑪哈。泰姬瑪哈曾經是我自幼心嚮往之的書 上的圖片，十年前，我終於去了，在那裡度過兩個黃昏然後回來，現在，一切又復歸是書上的圖片。 我只能說：『我去過了。』當然，我也還留著一些細節可以向你描述，譬如那向晚的輪廓模糊的平 原，還有從平原上吹過來的微微有點溫熱的風，粉紅與乳黃相併而成的大理石平台上，有幾朵隨風 落下的白色的素馨花。可是，也就只有這麼多了。而手邊所有的關於歷史的追溯，或者關於工程的 浩大與匠心等等都不過是旁白，是敘述用的資料，一如書上的圖片，只供導引與參考，卻絕不是事 件本身。」 下列選項，何者最符合上文旨意？', '["美感是切身感受，無法複製、保存或轉述", "再美的事物，未能親眼目睹，也僅是過眼雲煙", "旅行不僅提升眼界且增長人生智慧，終歸看山還是山", "在宏偉的歷史遺跡面前，任何文字都難以陳述過往的真實"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:01+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00709', 'elementary-0489de64', 'elementary-0489de64-moex-111-01c5eaab', 'sub-elementary-0489de64-05', NULL, 'single_choice', '「睡眠並非不清醒。睡眠遠勝於不清醒。夜間的睡眠精緻複雜，充滿活躍的代謝過程，而且有一系 列經過特意安排的獨特階段。腦中有無數功能的修復要仰賴睡眠，且並非單靠其中一種形式的睡眠 就能完成。睡眠的每個階段，包括淺度非快速動眼睡眠、深度非快速動眼睡眠、快速動眼睡眠，在 夜晚的不同時段對腦提供不同好處。因此，沒有某種形式的睡眠比另一種更重要。」 依據上文，最符合文意的選項為：', '["不清醒時與淺度睡眠狀態相似", "夜間的睡眠處於極度平靜狀態", "深度睡眠遠比淺度睡眠更可貴", "適度睡眠可即時修補大腦功能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:01+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00710', 'elementary-0489de64', 'elementary-0489de64-moex-111-01c5eaab', 'sub-elementary-0489de64-05', NULL, 'single_choice', '「很懷念小時候過年的感覺，有濃濃的趣味，各種糕點食品的味兒，大人難見的笑容，還有一種似 乎可以為所欲為、放鬆壓抑的興奮。人類學家發現，幾乎所有的民族都有自己的慶典。慶典的原始 目的有二：一是敬神祭祖；一是驅邪趕鬼。敬神包括祈福求平安，妻財子祿；驅邪包括治病求健康； 這病，也涵蓋心理及精神上的病。人類各種族的慶典，也有一共同的特色，就是大多都有一套制度 化的儀式，而儀式包括肅穆的典禮和狂放的歌舞酒食。現在過年不如以前來勁，乃是因為聖誕節、 情人節、中秋節等節慶已分批抒發了壓抑。所以，過年原來紓解情緒壓抑的功能就多餘了。」 下列選項，何者最不符合上文所述？', '["逢年過節可以盡情地放鬆壓抑、為所欲為", "慶典的原始目的是：敬神祭祖、驅邪趕鬼", "大多數的民族慶典，都有狂放的歌舞酒食", "多了其他節慶，使現在過年不如以前來勁"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:01+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "512", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL)
